static constexpr std::mdspan<uint64_t const, std::extents<int, n_sides, n_pieces, n_squares>> ptable{table.data()};
static constexpr std::mdspan<uint64_t const, std::extents<int, n_castling>>                   ctable{table.data()+ptable.size()};
static constexpr std::mdspan<uint64_t const, std::extents<int, n_enpassant>>                  etable{table.data()+ptable.size()+ctable.size()};
static constexpr auto                                                                          side{11001561807031406013UL};

auto hasher::operator()(chesslib::board const& b) const -> uint64_t {
    auto h{0UL};

    auto const& s = b.state();
    for (auto k = 0; std::cmp_less(k, encoding::length); ++k) {
        if (!coord::valid(k)) { continue; }
        if (b.piece_at(k) == piece::none) { continue; }
        auto const [p, c] = b[k];

        auto const i = static_cast<int>(c); // color index
        auto const j = static_cast<int>(p); // piece index
        ASSERT(i < n_sides);
        ASSERT(j < n_pieces);
        ASSERT(k < n_squares);
        h ^= ptable(i, j, k);
    }

    if (static_cast<u8>(s.castling)) {
        h ^= ctable(static_cast<int>(s.castling));
    }

    if (s.enpassant != square::none) {
        h ^= etable(coord::file(s.enpassant));
    }

    if (b.black_to_move()) {
        h ^= side;
    }
    return h;
}

auto hasher::piece(int i, int j, int k) -> uint64_t {
    return ptable(i, j, k);
}

auto hasher::enpassant_file(int file) -> uint64_t {
    return etable(file);
}

auto hasher::side_to_move() -> uint64_t {
    return side;
}

